105	// NewDecomposePostLadderExhaustionHook creates a PostLadderExhaustionHook that
106	// dispatches runDecomposer for TooLarge failure class.
107	func NewDecomposePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
108		return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
109			if failureClass != TooLarge {
110				return &PostLadderExhaustionResult{Attempted: false}, nil
111			}
112			result := runDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
113			if result.Failed {
114				return &PostLadderExhaustionResult{
115					Attempted: true,
116					Succeeded: false,
117					Path:      Decompose,
118					CostUSD:   result.CostUSD,
119				}, nil
120			}
121			return &PostLadderExhaustionResult{
122				Attempted: true,
123				Succeeded: true,
124				Path:      Decompose,
125				CostUSD:   result.CostUSD,
126			}, nil
127		}
128	}
