130	// runDecomposer dispatches a smart+ powerClass agent to split the bead into child
131	// beads after the escalation ladder has been exhausted. On success, child beads
132	// are created with Parent=beadID, the parent's execution-eligible is set to
133	// false, and a "decompose-applied" event is emitted. On failure a
134	// DecomposeResult with Failed=true is returned.
135	func runDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) DecomposeResult {
136		tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
137		defer cancel()
138	
139		b, err := store.Get(ctx, beadID)
140		if err != nil {
141			return DecomposeResult{Failed: true, Reason: "store_error"}
142		}
143	
144		prompt, err := buildDecomposerPrompt(store, b)
145		if err != nil {
146			return DecomposeResult{Failed: true, Reason: "prompt_error"}
147		}
148	
149		runtime := AgentRunRuntime{
150			Prompt:           prompt,
151			PromptSource:     decomposerPromptSource,
152			ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
153			ClearRoutingPins: true,
154			ClearProfile:     true,
155			ClearMinPower:    true,
156			ClearMaxPower:    true,
157		}
158	
159		result, err := dispatchLifecycleRun(tctx, projectRoot, nil, runner, rcfg, runtime)
160		if err != nil && result == nil {
161			if tctx.Err() != nil {
162				return DecomposeResult{Failed: true, Reason: "timeout"}
163			}
164			return DecomposeResult{Failed: true, Reason: "dispatch_error"}
165		}
166	
167		output := strings.TrimSpace(result.CondensedOutput)
168		if output == "" {
169			output = strings.TrimSpace(result.Output)
170		}
171		if output == "" {
172			return DecomposeResult{Failed: true, Reason: "empty_output", CostUSD: result.CostUSD}
173		}
174	
175		children, ok := parseDecomposerOutput(output)
176		if !ok {
177			return DecomposeResult{Failed: true, Reason: "invalid_output", CostUSD: result.CostUSD}
178		}
179	
180		if len(children) < 1 || len(children) > 5 {
181			return DecomposeResult{Failed: true, Reason: "invalid_count", CostUSD: result.CostUSD}
182		}
183	
184		for _, child := range children {
185			if strings.TrimSpace(child.Title) == "" ||
186				strings.TrimSpace(child.Description) == "" ||
187				strings.TrimSpace(child.Acceptance) == "" {
188				return DecomposeResult{Failed: true, Reason: "malformed_child", CostUSD: result.CostUSD}
189			}
190		}
191	
192		childIDs := make([]string, 0, len(children))
193		for _, child := range children {
194			nb := &bead.Bead{
195				Title:       strings.TrimSpace(child.Title),
196				Description: strings.TrimSpace(child.Description),
197				Acceptance:  strings.TrimSpace(child.Acceptance),
198				Labels:      append([]string(nil), child.Labels...),
199				Parent:      beadID,
200			}
201			if err := store.Create(context.Background(), nb); err != nil {
202				return DecomposeResult{Failed: true, Reason: "create_error"}
203			}
204			childIDs = append(childIDs, nb.ID)
205		}
206	
207		_ = store.Update(context.Background(), beadID, func(b *bead.Bead) {
208			ensureBeadExtra(b)
209			b.Extra[bead.ExtraExecutionElig] = false
210		})
211	
212		body, _ := json.Marshal(decomposerEventBody{
213			ChildIDs: childIDs,
214			CostUSD:  result.CostUSD,
215		})
216		_ = store.AppendEvent(beadID, bead.BeadEvent{
217			Kind:      "decompose-applied",
218			Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
219			Body:      string(body),
220			Actor:     "ddx work",
221			Source:    "ddx work",
222			CreatedAt: time.Now().UTC(),
223		})
224	
225		return DecomposeResult{
226			Failed:   false,
227			ChildIDs: childIDs,
228			CostUSD:  result.CostUSD,
229		}
230	}
