232	func buildDecomposerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
233		type failureEntry struct {
234			Summary string `json:"summary"`
235			Body    string `json:"body,omitempty"`
236		}
237		type envelope struct {
238			Title          string         `json:"title"`
239			Description    string         `json:"description"`
240			Acceptance     string         `json:"acceptance"`
241			FailureHistory []failureEntry `json:"failure_history"`
242		}
243	
244		env := envelope{
245			Title:       strings.TrimSpace(b.Title),
246			Description: strings.TrimSpace(b.Description),
247			Acceptance:  strings.TrimSpace(b.Acceptance),
248		}
249	
250		if events, err := store.Events(b.ID); err == nil {
251			for i := len(events) - 1; i >= 0 && len(env.FailureHistory) < 5; i-- {
252				ev := events[i]
253				switch ev.Kind {
254				case "bead.result", "execute-bead", "per-bead-budget-exhausted":
255				default:
256					continue
257				}
258				env.FailureHistory = append(env.FailureHistory, failureEntry{
259					Summary: strings.TrimSpace(ev.Summary),
260					Body:    strings.TrimSpace(ev.Body),
261				})
262			}
263		}
264	
265		body, err := json.MarshalIndent(env, "", "  ")
266		if err != nil {
267			return "", fmt.Errorf("decomposer: encode prompt: %w", err)
268		}
269	
270		var sb strings.Builder
271		sb.WriteString("MODE: decompose\n")
272		sb.WriteString("You are splitting a bead that is too large into 2-5 independently executable child beads.\n")
273		sb.WriteString("Each child must have a self-contained description, 3-6 numbered ACs with at least one named test function.\n")
274		sb.WriteString("Return exactly one JSON array of child spec objects: [{\"title\":...,\"description\":...,\"acceptance\":...,\"labels\":[...]}]\n")
275		sb.WriteString("Do not include prose or markdown; return only the JSON array.\n\n")
276		sb.WriteString("```json\n")
277		sb.Write(body)
278		sb.WriteString("\n```\n")
279		return sb.String(), nil
280	}
