282	// parseDecomposerOutput extracts a JSON array of child specs from agent output.
283	func parseDecomposerOutput(output string) ([]decomposerChild, bool) {
284		if c, ok := lastFencedBlock(output, "json"); ok {
285			var children []decomposerChild
286			if err := json.Unmarshal([]byte(strings.TrimSpace(c)), &children); err == nil {
287				return children, true
288			}
289		}
290		if c, ok := lastFencedBlock(output, ""); ok {
291			trimmed := strings.TrimSpace(c)
292			if strings.HasPrefix(trimmed, "[") {
293				var children []decomposerChild
294				if err := json.Unmarshal([]byte(trimmed), &children); err == nil {
295					return children, true
296				}
297			}
298		}
299		// Scan for first '[' and balance brackets to find a raw JSON array.
300		start := strings.Index(output, "[")
301		if start == -1 {
302			return nil, false
303		}
304		depth := 0
305		for i := start; i < len(output); i++ {
306			switch output[i] {
307			case '[':
308				depth++
309			case ']':
310				depth--
311				if depth == 0 {
312					var children []decomposerChild
313					if err := json.Unmarshal([]byte(output[start:i+1]), &children); err == nil {
314						return children, true
315					}
316					return nil, false
317				}
318			}
319		}
320		return nil, false
321	}
