377	func parsePreClaimDecompositionOutput(output string) (*PreClaimDecomposition, bool) {
378		if c, ok := lastFencedBlock(output, "json"); ok {
379			output = strings.TrimSpace(c)
380		} else if c, ok := extractJSONCandidate(output); ok {
381			output = strings.TrimSpace(c)
382		}
383		var decomp PreClaimDecomposition
384		if err := json.Unmarshal([]byte(output), &decomp); err != nil {
385			return nil, false
386		}
387		return &decomp, true
388	}
