390	func validatePreClaimDecomposition(decomp *PreClaimDecomposition) error {
391		if decomp == nil {
392			return fmt.Errorf("decomposer: nil decomposition")
393		}
394		if len(decomp.Children) < 1 || len(decomp.Children) > 5 {
395			return fmt.Errorf("decomposer: invalid child count %d", len(decomp.Children))
396		}
397		for i := range decomp.Children {
398			child := &decomp.Children[i]
399			child.Title = strings.TrimSpace(child.Title)
400			child.Description = strings.TrimSpace(child.Description)
401			child.Acceptance = strings.TrimSpace(child.Acceptance)
402			if child.Title == "" || child.Description == "" || child.Acceptance == "" {
403				return fmt.Errorf("decomposer: malformed child %d", i+1)
404			}
405		}
406		for i := range decomp.ACMap {
407			decomp.ACMap[i].ParentAC = strings.TrimSpace(decomp.ACMap[i].ParentAC)
408			decomp.ACMap[i].Coverage = strings.TrimSpace(decomp.ACMap[i].Coverage)
409		}
410		decomp.Rationale = strings.TrimSpace(decomp.Rationale)
411		return nil
412	}
