414	func fallbackPreClaimDecomposition(b *bead.Bead, reason string) (*PreClaimDecomposition, error) {
415		items := numberedAcceptanceItems(b.Acceptance)
416		if len(items) == 0 {
417			items = []string{
418				"Implement the first bounded slice of the parent bead.",
419				"Implement the remaining bounded slice of the parent bead.",
420			}
421		}
422		childCount := 2
423		if len(items) >= 12 {
424			childCount = 5
425		} else if len(items) >= 9 {
426			childCount = 4
427		} else if len(items) >= 5 {
428			childCount = 3
429		}
430		if childCount > len(items) {
431			childCount = len(items)
432		}
433		if childCount < 1 {
434			return nil, fmt.Errorf("fallback decomposer: no child scopes")
435		}
436	
437		chunks := chunkStrings(items, childCount)
438		children := make([]PreClaimDecompositionChild, 0, len(chunks))
439		acMap := make([]ACMapEntry, 0, len(items))
440		parentSummary := clampForPrompt(strings.TrimSpace(b.Description), 2400)
441		if parentSummary == "" {
442			parentSummary = strings.TrimSpace(b.Title)
443		}
444		baseLabels := append([]string(nil), b.Labels...)
445		baseLabels = appendUniqueLabel(baseLabels, "decomposed")
446		for i, chunk := range chunks {
447			if len(chunk) == 0 {
448				continue
449			}
450			title := fallbackChildTitle(b.Title, i+1)
451			description := fallbackChildDescription(b, parentSummary, chunk, i+1, len(chunks))
452			acceptance := fallbackChildAcceptance(chunk, b.Acceptance)
453			children = append(children, PreClaimDecompositionChild{
454				Title:       title,
455				Description: description,
456				Acceptance:  acceptance,
457				Labels:      append([]string(nil), baseLabels...),
458			})
459			for _, item := range chunk {
460				acMap = append(acMap, ACMapEntry{
461					ParentAC: item,
462					Coverage: fmt.Sprintf("covered by child %d: %s", i+1, title),
463				})
464			}
465		}
466		if len(children) == 0 {
467			return nil, fmt.Errorf("fallback decomposer: no child scopes")
468		}
469		return &PreClaimDecomposition{
470			Children:  children,
471			ACMap:     acMap,
472			Rationale: "deterministic fallback split after agent decomposer returned " + strings.TrimSpace(reason),
473		}, nil
474	}
