476	func numberedAcceptanceItems(acceptance string) []string {
477		lines := strings.Split(acceptance, "\n")
478		items := make([]string, 0, len(lines))
479		for _, line := range lines {
480			trimmed := strings.TrimSpace(line)
481			dot := strings.Index(trimmed, ".")
482			if dot <= 0 {
483				continue
484			}
485			prefix := trimmed[:dot]
486			if _, err := fmt.Sscanf(prefix, "%d", new(int)); err != nil {
487				continue
488			}
489			item := strings.TrimSpace(trimmed[dot+1:])
490			if item != "" {
491				items = append(items, item)
492			}
493		}
494		return items
495	}
496	
497	func chunkStrings(items []string, chunks int) [][]string {
498		if chunks <= 0 {
499			return nil
500		}
501		out := make([][]string, 0, chunks)
502		for i := 0; i < chunks; i++ {
503			start := i * len(items) / chunks
504			end := (i + 1) * len(items) / chunks
505			out = append(out, items[start:end])
506		}
507		return out
508	}
