510	func fallbackChildTitle(parentTitle string, n int) string {
511		title := strings.TrimSpace(parentTitle)
512		if len(title) > 72 {
513			title = strings.TrimSpace(title[:72])
514		}
515		if title == "" {
516			title = "decomposed bead"
517		}
518		return fmt.Sprintf("%s: part %d", title, n)
519	}
