521	func fallbackChildDescription(parent *bead.Bead, parentSummary string, chunk []string, n, total int) string {
522		var sb strings.Builder
523		sb.WriteString("PROBLEM\n")
524		sb.WriteString("Parent bead ")
525		sb.WriteString(parent.ID)
526		sb.WriteString(" is too broad for one execution pass. This child owns part ")
527		sb.WriteString(fmt.Sprintf("%d of %d", n, total))
528		sb.WriteString(" of that parent scope.\n\nROOT CAUSE\n")
529		sb.WriteString(parentSummary)
530		sb.WriteString("\n\nPROPOSED FIX\nImplement only this child acceptance slice:\n")
531		for _, item := range chunk {
532			sb.WriteString("- ")
533			sb.WriteString(item)
534			sb.WriteByte('\n')
535		}
536		sb.WriteString("\nNON-SCOPE\nDo not implement parent acceptance criteria assigned to sibling child beads. Preserve every parent non-scope constraint unless this child explicitly narrows it.")
537		return sb.String()
538	}
