540	func fallbackChildAcceptance(chunk []string, parentAcceptance string) string {
541		var sb strings.Builder
542		for i, item := range chunk {
543			sb.WriteString(fmt.Sprintf("%d. %s\n", i+1, item))
544		}
545		next := len(chunk) + 1
546		if !strings.Contains(parentAcceptance, "go test") {
547			sb.WriteString(fmt.Sprintf("%d. cd cli && go test ./... passes.\n", next))
548			next++
549		}
550		if !strings.Contains(parentAcceptance, "lefthook run pre-commit") {
551			sb.WriteString(fmt.Sprintf("%d. lefthook run pre-commit passes.\n", next))
552		}
553		return strings.TrimSpace(sb.String())
554	}
