9	// BlockReasonCode is the closed taxonomy of reasons an open bead is non-ready
10	// in the idle-path diagnosis pass. The full set is defined by FEAT-010
11	// §Idle-Path Diagnosis and Auto-Remediation; new codes require that spec to
12	// be updated.
13	type BlockReasonCode string
14	
15	const (
16		ReasonSupersededPendingClose              BlockReasonCode = "superseded_pending_close"
17		ReasonClosureCandidateMisclassified       BlockReasonCode = "closure_candidate_misclassified"
18		ReasonDeadIntermediateAllChildrenClosed   BlockReasonCode = "dead_intermediate_all_children_closed"
19		ReasonDeadIntermediateOpenChildrenPending BlockReasonCode = "dead_intermediate_open_children_pending"
20		ReasonEpicOfEpic                          BlockReasonCode = "epic_of_epic"
21		ReasonDepBlockedBy                        BlockReasonCode = "dep_blocked_by"
22		ReasonGenuinelyNeedsDecomposition         BlockReasonCode = "genuinely_needs_decomposition"
23		ReasonParentChildStateConflict            BlockReasonCode = "parent_child_state_conflict"
24		ReasonClaimedInProgress                   BlockReasonCode = "claimed_in_progress"
25		ReasonProviderRouteUnavailable            BlockReasonCode = "provider_route_unavailable"
26		ReasonGatedByBudgetOrCooldown             BlockReasonCode = "gated_by_budget_or_cooldown"
27		ReasonMalformedParentOrDepRef             BlockReasonCode = "malformed_parent_or_dep_ref"
28		ReasonDependencyCycle                     BlockReasonCode = "dependency_cycle"
29		ReasonClosedOrMissingParent               BlockReasonCode = "closed_or_missing_parent"
30		ReasonStaleGraphIndex                     BlockReasonCode = "stale_graph_index"
31		ReasonAutoRemediationExhausted            BlockReasonCode = "auto_remediation_exhausted"
32		ReasonNoDiagnosis                         BlockReasonCode = "no_diagnosis"
33	)
