35	// BlockReason is a per-bead diagnosis of why a bead is non-ready. Detail is a
36	// human-readable string suitable for surfacing to operators; CitedIDs lists
37	// other bead IDs the reason references (deps, supersession targets, parents,
38	// cycle participants).
39	type BlockReason struct {
40		Code     BlockReasonCode
41		Detail   string
42		CitedIDs []string
43	}
44	
45	// Diagnose returns the first matching BlockReason for b according to the
46	// FEAT-010 §Idle-Path Diagnosis and Auto-Remediation taxonomy. The caller
47	// must pre-build the indexes:
48	//
49	//   - childIndex: parent_id -> every child bead (any status). Root beads are
50	//     keyed under the empty string. Diagnose also uses childIndex as the
51	//     global bead lookup; every referenced bead (supersession target, dep
52	//     target, parent) must appear in some entry for Diagnose to verify its
53	//     state.
54	//   - openChildIndex: parent_id -> open child beads only.
55	//   - depIndex: bead_id -> outgoing Dependency entries for that bead. Used
56	//     for global cycle detection across the dep DAG.
57	//
58	// Diagnose is pure: it performs no I/O, does not consult global state, and
59	// does not mutate its inputs.
60	func Diagnose(
61		b Bead,
62		childIndex map[string][]Bead,
63		openChildIndex map[string][]Bead,
64		depIndex map[string][]Dependency,
65	) BlockReason {
66		// 1. superseded_pending_close
67		if y := supersedingTargetID(b); y != "" {
68			if target, ok := lookupBead(childIndex, y); ok && target.Status == StatusClosed {
69				return BlockReason{
70					Code:     ReasonSupersededPendingClose,
71					Detail:   fmt.Sprintf("superseded by closed bead %s", y),
72					CitedIDs: []string{y},
73				}
74			}
75		}
76	
77		total := len(childIndex[b.ID])
78		open := len(openChildIndex[b.ID])
79	
80		// 2. closure_candidate_misclassified — epic with closure-ready child set
81		if isEpicBead(b) && total > 0 && open == 0 {
82			return BlockReason{
83				Code:   ReasonClosureCandidateMisclassified,
84				Detail: fmt.Sprintf("epic %s has %d children, none open", b.ID, total),
85			}
86		}
87	
88		// 3 & 4. dead_intermediate_* — bead opted out of execution
89		if eligible, set := lifecycleExecutionEligible(b); set && !eligible {
90			if total > 0 && open == 0 {
91				return BlockReason{
92					Code:   ReasonDeadIntermediateAllChildrenClosed,
93					Detail: "execution-eligible=false; all children closed",
94				}
95			}
96			if open > 0 {
97				ids := beadIDsFrom(openChildIndex[b.ID])
98				return BlockReason{
99					Code:     ReasonDeadIntermediateOpenChildrenPending,
100					Detail:   fmt.Sprintf("execution-eligible=false; %d open child(ren) pending", open),
101					CitedIDs: ids,
102				}
103			}
104		}
105	
106		// 5. epic_of_epic — only open descendants are themselves epics
107		if open > 0 {
108			openChildren := openChildIndex[b.ID]
109			if allEpicBeads(openChildren) {
110				return BlockReason{
111					Code:     ReasonEpicOfEpic,
112					Detail:   "only open children are themselves epics",
113					CitedIDs: beadIDsFrom(openChildren),
114				}
115			}
116		}
117	
118		// 6. dep_blocked_by — unresolved outgoing deps
119		if blockers := openDepBlockers(b, childIndex); len(blockers) > 0 {
120			ids := make([]string, 0, len(blockers))
121			details := make([]string, 0, len(blockers))
122			for _, blk := range blockers {
123				ids = append(ids, blk.ID)
124				details = append(details, fmt.Sprintf("%s(status=%s)", blk.ID, blk.Status))
125			}
126			return BlockReason{
127				Code:     ReasonDepBlockedBy,
128				Detail:   "dep_blocked_by:" + strings.Join(details, ","),
129				CitedIDs: ids,
130			}
131		}
132	
133		// 7. genuinely_needs_decomposition
134		if isEpicBead(b) && total == 0 && !hasDecompositionOverrideLabel(b) {
135			return BlockReason{
136				Code:   ReasonGenuinelyNeedsDecomposition,
137				Detail: "epic with no children and no manual-hold/no-auto-decompose/container override",
138			}
139		}
140	
141		// 8. parent_child_state_conflict
142		if msg := parentChildConflict(b, childIndex); msg != "" {
143			return BlockReason{
144				Code:   ReasonParentChildStateConflict,
145				Detail: msg,
146			}
147		}
148	
149		// 9. claimed_in_progress
150		if b.Status == StatusInProgress {
151			return BlockReason{
152				Code:   ReasonClaimedInProgress,
153				Detail: "bead currently claimed by an active worker",
154			}
155		}
156	
157		// 10. provider_route_unavailable
158		if isProviderRouteUnavailable(b) {
159			return BlockReason{
160				Code:   ReasonProviderRouteUnavailable,
161				Detail: "last dispatch: " + providerRouteHint(b),
162			}
163		}
164	
165		// 11. gated_by_budget_or_cooldown
166		if gate := budgetOrCooldownGate(b); gate != "" {
167			return BlockReason{
168				Code:   ReasonGatedByBudgetOrCooldown,
169				Detail: gate,
170			}
171		}
172	
173		// 12. malformed_parent_or_dep_ref
174		if msg, cited := malformedRef(b, childIndex); msg != "" {
175			return BlockReason{
176				Code:     ReasonMalformedParentOrDepRef,
177				Detail:   msg,
178				CitedIDs: cited,
179			}
180		}
181	
182		// 13. dependency_cycle
183		if cycle := detectDepCycle(b.ID, depIndex); len(cycle) > 0 {
184			return BlockReason{
185				Code:     ReasonDependencyCycle,
186				Detail:   "cycle: " + strings.Join(cycle, "->"),
187				CitedIDs: cycle,
188			}
189		}
190	
191		// 14. closed_or_missing_parent
192		if b.Parent != "" {
193			if parent, ok := lookupBead(childIndex, b.Parent); ok && parent.Status == StatusClosed {
194				return BlockReason{
195					Code:     ReasonClosedOrMissingParent,
196					Detail:   fmt.Sprintf("parent %s is closed", b.Parent),
197					CitedIDs: []string{b.Parent},
198				}
199			}
200		}
201	
202		// 15. stale_graph_index
203		if msg := staleIndexDisagreement(b, childIndex, openChildIndex); msg != "" {
204			return BlockReason{
205				Code:   ReasonStaleGraphIndex,
206				Detail: msg,
207			}
208		}
209	
210		// 16. auto_remediation_exhausted
211		if isAutoRemediationExhausted(b) {
212			return BlockReason{
213				Code:   ReasonAutoRemediationExhausted,
214				Detail: "auto-remediation attempts cap hit or cooldown active",
215			}
216		}
217	
218		// 17. no_diagnosis (fallback)
219		return BlockReason{
220			Code:   ReasonNoDiagnosis,
221			Detail: "no diagnosis matched; surface as bug",
222		}
223	}
