267	// isEpicBead matches the bead-container classifier used by the lifecycle
268	// queue: explicit issue_type==epic or a title prefix of "epic:" or "epic ".
269	func isEpicBead(b Bead) bool {
270		issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
271		if issueType == "epic" {
272			return true
273		}
274		title := strings.ToLower(strings.TrimSpace(b.Title))
275		return strings.HasPrefix(title, "epic:") || strings.HasPrefix(title, "epic ")
276	}
