// TestAutoDecomposeEpic_FailureSetsCooldown validates that when the decomposer
// returns a failure, a 15m cooldown is set and auto_decompose_failed event is emitted.
func TestAutoDecomposeEpic_FailureSetsCooldown(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{
		ID:          "ddx-failure-cooldown",
		Title:       "epic: failure cooldown",
		IssueType:   "epic",
		Description: "PROBLEM\nTest.\n\nROOT CAUSE\nTest.\n\nPROPOSED FIX\nTest.\n",
		Acceptance:  "1. Test passes\n",
		Labels:      []string{"spec:FEAT-010"},
	}
	require.NoError(t, store.Create(b))

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	decomposeRunner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
		return &Result{
			ExitCode: 1,
			Output:   "decomposition failed",
		}, fmt.Errorf("decomposer error")
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	result, err := AutoDecomposeEpic(ctx, store, decomposeRunner, rcfg, t.TempDir(), b.ID)

	require.NoError(t, err)
	assert.True(t, result.Failed)

	// Verify cooldown was set
	updated, err := store.Get(context.Background(), b.ID)
	require.NoError(t, err)
	retryAfterStr := extraStringVal(updated.Extra, bead.ExtraRetryAfter)
	assert.NotEmpty(t, retryAfterStr, "retry-after cooldown must be set")
	retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
	require.NoError(t, err)
	now := time.Now().UTC()
	assert.True(t, retryAfter.After(now), "retry-after must be in the future")
	assert.True(t, retryAfter.Before(now.Add(20*time.Minute)), "retry-after must be ~15m from now")

	// Verify auto_decompose_failed event was emitted
	events, err := store.Events(b.ID)
	require.NoError(t, err)
	var foundFailedEvent bool
	for _, ev := range events {
		if ev.Kind == autoDecomposeFailedEventKind {
			foundFailedEvent = true
		}
	}
	assert.True(t, foundFailedEvent, "auto_decompose_failed event must be emitted")
}

