// getChildCounts returns the total and open child counts for a bead.
func getChildCounts(store ExecuteBeadLoopStore, b *bead.Bead) (total, open int, err error) {
	beads, err := store.ReadAll(context.Background())
	if err != nil {
		return 0, 0, err
	}
	for _, candidate := range beads {
		if candidate.Parent == b.ID {
			total++
			if candidate.Status != bead.StatusClosed && candidate.Status != bead.StatusCancelled {
				open++
			}
		}
	}
	return total, open, nil
}

// buildChildIndexFromStore builds a child index from all beads in the store.
// This is used by Diagnose; beads are keyed by parent ID with roots under "".
func buildChildIndexFromStore(store ExecuteBeadLoopStore, beadID string) map[string][]bead.Bead {
	beads, err := store.ReadAll(context.Background())
	if err != nil {
		return map[string][]bead.Bead{}
	}
	index := make(map[string][]bead.Bead)
	for _, b := range beads {
		parent := b.Parent
		if parent == "" {
			parent = ""
		}
		index[parent] = append(index[parent], b)
	}
	return index
}

// buildOpenChildIndexFromStore builds an open-child index from all beads in the store.
// Only beads with open status are included.
func buildOpenChildIndexFromStore(store ExecuteBeadLoopStore, beadID string) map[string][]bead.Bead {
	beads, err := store.ReadAll(context.Background())
	if err != nil {
		return map[string][]bead.Bead{}
	}
	index := make(map[string][]bead.Bead)
	for _, b := range beads {
		if b.Status == bead.StatusClosed || b.Status == bead.StatusCancelled {
			continue
		}
		parent := b.Parent
		if parent == "" {
			parent = ""
		}
		index[parent] = append(index[parent], b)
	}
