}

// buildDepIndexFromStore builds a dependency index from all beads in the store.
// Maps bead_id -> outgoing Dependency entries.
func buildDepIndexFromStore(store ExecuteBeadLoopStore) map[string][]bead.Dependency {
	beads, err := store.ReadAll(context.Background())
	if err != nil {
		return map[string][]bead.Dependency{}
	}
	index := make(map[string][]bead.Dependency)
	for _, b := range beads {
		index[b.ID] = append(index[b.ID], b.Dependencies...)
	}
	return index
}

